// Get row 1 data from direct input (GET request)
const row1 = $input.first().json.values?.[0] || [];
const nextCol = row1.length;

function colToLetter(col) {
  let letter = '';
  while (col >= 0) {
    letter = String.fromCharCode((col % 26) + 65) + letter;
    col = Math.floor(col / 26) - 1;
  }
  return letter;
}

const colLetter = colToLetter(nextCol);
const c = colLetter;

// Calculate next week date
const lastDateStr = row1[row1.length - 1];
const parts = lastDateStr.split('-');
const months = {'Jan':0,'Feb':1,'Mar':2,'Apr':3,'May':4,'Jun':5,'Jul':6,'Aug':7,'Sep':8,'Oct':9,'Nov':10,'Dec':11};
const lastDate = new Date(parseInt(parts[2]), months[parts[1]], parseInt(parts[0]));
const nextMonday = new Date(lastDate);
nextMonday.setDate(lastDate.getDate() + 7);
const weekStarting = `${nextMonday.getDate()}-${nextMonday.toLocaleString('en-GB', {month: 'short'})}-${nextMonday.getFullYear()}`;

// Get sales and views from Merge node
// CHANGE 'Merge' to your actual Merge node name
const mergeData = $('Merge').all();
const salesText = mergeData[0].json.output[0].content[0].text;
const viewsText = mergeData[1].json.output[0].content[0].text;

const sales = {};
salesText.split('\n').forEach(line => {
  const match = line.match(/(\w+) Sales:\s*([\d,]+)/);
  if (match) sales[match[1]] = parseInt(match[2].replace(/,/g, ''));
});

const views = {};
viewsText.split('\n').forEach(line => {
  const match = line.match(/(\w+) unique page views:\s*([\d,]+)/);
  if (match) views[match[1]] = parseInt(match[2].replace(/,/g, ''));
});

const values = [
  [weekStarting],
  [''],
  [views['LPP'] || 0],
  [`=IF(${c}3>0,${c}5/${c}3,0)`],
  [sales['LPP'] || 0],
  [views['NLP'] || 0],
  [`=IF(${c}6>0,${c}8/${c}6,0)`],
  [sales['NLP'] || 0],
  [views['AA'] || 0],
  [`=IF(${c}9>0,${c}11/${c}9,0)`],
  [sales['AA'] || 0],
  [views['LS'] || 0],
  [`=IF(${c}12>0,${c}14/${c}12,0)`],
  [sales['LS'] || 0],
  [views['EE'] || 0],
  [`=IF(${c}15>0,${c}17/${c}15,0)`],
  [sales['EE'] || 0],
  [`=${c}3+${c}6+${c}9+${c}12+${c}15`],
  [`=IF(${c}18>0,${c}20/${c}18,0)`],
  [`=${c}5+${c}8+${c}11+${c}14+${c}17`],
];

return [{ 
  json: { 
    range: `'Data Weekly'!${c}1:${c}20`,
    values,
    colIndex: nextCol
  } 
}];

