const today = new Date();
const dayOfWeek = today.getDay(); // 0=Sun, 1=Mon, ...

// Last Monday = go back to this Monday, then subtract 7
const thisMonday = new Date(today);
thisMonday.setDate(today.getDate() - (dayOfWeek === 0 ? 6 : dayOfWeek - 1));
const lastMonday = new Date(thisMonday);
lastMonday.setDate(thisMonday.getDate() - 7);
const lastSunday = new Date(lastMonday);
lastSunday.setDate(lastMonday.getDate() + 6);

// Format as "Feb 10, 2026" for SamCart
const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const startDate = `${months[lastMonday.getMonth()]} ${lastMonday.getDate()}, ${lastMonday.getFullYear()}`;
const endDate = `${months[lastSunday.getMonth()]} ${lastSunday.getDate()}, ${lastSunday.getFullYear()}`;

return [{
  json: {
    startDate,
    endDate,
    // Also useful for GA which might need different format
    startISO: lastMonday.toISOString().split('T')[0],
    endISO: lastSunday.toISOString().split('T')[0],
  }
}];

