// Get row 1 data from direct input (GET request)
const row1 = $input.first().json.values?.[0] || [];
const nextCol = row1.length;

function colToLetter(col) {
  let letter = '';
  while (col >= 0) {
    letter = String.fromCharCode((col % 26) + 65) + letter;
    col = Math.floor(col / 26) - 1;
  }
  return letter;
}

const colLetter = colToLetter(nextCol);
const c = colLetter;

// Calculate next month from the last column header
const lastDateStr = row1[row1.length - 1];
const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const parts = lastDateStr.split(' ');
const monthIndex = monthNames.indexOf(parts[0]);
const year = parseInt(parts[1]);

const nextMonthDate = new Date(year, monthIndex + 1, 1);
const monthHeader = `${monthNames[nextMonthDate.getMonth()]} ${nextMonthDate.getFullYear()}`;

// Get sales, views, and leads from Merge node
const mergeData = $('Merge Monthly').all();
const salesText = mergeData[0].json.output[0].content[0].text;
const viewsText = mergeData[1].json.output[0].content[0].text;
const leadsText = mergeData[2].json.output[0].content[0].text;

// Parse sales - separate core+plan from order bump
const coreSales = {};
const bumpSales = {};
let currentSection = '';

salesText.split('\n').forEach(line => {
  const trimmed = line.trim();
  if (trimmed.toLowerCase().startsWith('core')) {
    currentSection = 'core';
    return;
  }
  if (trimmed.toLowerCase().startsWith('order bump')) {
    currentSection = 'bump';
    return;
  }
  const match = trimmed.match(/(\w+) Sales:\s*([\d,]+)/);
  if (match) {
    const key = match[1];
    const val = parseInt(match[2].replace(/,/g, ''));
    if (currentSection === 'bump') {
      bumpSales[key] = val;
    } else {
      coreSales[key] = val;
    }
  }
});

// Parse views
const views = {};
viewsText.split('\n').forEach(line => {
  const match = line.match(/(\w+) unique page views:\s*([\d,]+)/);
  if (match) views[match[1]] = parseInt(match[2].replace(/,/g, ''));
});

// Parse leads and unsubscribes
let totalNewLeads = 0;
let unsubscribes = 0;
leadsText.split('\n').forEach(line => {
  const leadsMatch = line.match(/Total new leads:\s*([\d,]+)/i);
  if (leadsMatch) totalNewLeads = parseInt(leadsMatch[1].replace(/,/g, ''));
  const unsubMatch = line.match(/Unsubscribes:\s*([\d,]+)/i);
  if (unsubMatch) unsubscribes = parseInt(unsubMatch[1].replace(/,/g, ''));
});

const totalViews = (views['LPP'] || 0) + (views['NLP'] || 0) + (views['AA'] || 0) + (views['LS'] || 0) + (views['EE'] || 0);
const totalCoreSales = (coreSales['LPP'] || 0) + (coreSales['NLP'] || 0) + (coreSales['AA'] || 0) + (coreSales['LS'] || 0) + (coreSales['EE'] || 0);
const totalBumpSales = (bumpSales['LPP'] || 0) + (bumpSales['NLP'] || 0) + (bumpSales['AA'] || 0) + (bumpSales['LS'] || 0) + (bumpSales['EE'] || 0);

const values = [
  [monthHeader],                                     // Row 1: Month header
  [''],                                              // Row 2: Sales Page performance
  [1],                                               // Row 3: LPP Bonus unique page views (legacy)
  [`=IF(${c}3>0,${c}5/${c}3,0)`],                   // Row 4: Conversion rate (legacy)
  [0],                                               // Row 5: Sales (legacy)
  [views['LPP'] || 0],                               // Row 6: LPP No Bonus unique page views
  [`=IF(${c}6>0,${c}8/${c}6,0)`],                   // Row 7: LPP conversion
  [coreSales['LPP'] || 0],                           // Row 8: LPP core sales
  [views['NLP'] || 0],                               // Row 9: NLP unique page views
  [`=IF(${c}9>0,${c}11/${c}9,0)`],                  // Row 10: NLP conversion
  [coreSales['NLP'] || 0],                           // Row 11: NLP core sales
  [views['AA'] || 0],                                // Row 12: AA unique page views
  [`=IF(${c}12>0,${c}14/${c}12,0)`],                // Row 13: AA conversion
  [coreSales['AA'] || 0],                            // Row 14: AA core sales
  [views['LS'] || 0],                                // Row 15: LS unique page views
  [`=IF(${c}15>0,${c}17/${c}15,0)`],                // Row 16: LS conversion
  [coreSales['LS'] || 0],                            // Row 17: LS core sales
  [views['EE'] || 0],                                // Row 18: EE unique page views
  [`=IF(${c}18>0,${c}20/${c}18,0)`],                // Row 19: EE conversion
  [coreSales['EE'] || 0],                            // Row 20: EE core sales
  [bumpSales['LPP'] || 0],                           // Row 21: LPP Order Bump
  [bumpSales['NLP'] || 0],                           // Row 22: NLP Order Bump
  [bumpSales['AA'] || 0],                            // Row 23: AA Order Bump
  [bumpSales['LS'] || 0],                            // Row 24: LS Order Bump
  [bumpSales['EE'] || 0],                            // Row 25: EE Order Bump
  [`=${c}8+${c}11+${c}14+${c}17+${c}20+${c}21+${c}22+${c}23+${c}24+${c}25`], // Row 26: Total sales all courses
  [''],                                              // Row 27: blank
  [totalNewLeads],                                   // Row 28: Total new Leads
  [unsubscribes],                                    // Row 29: Unsubscribes
];

return [{ 
  json: { 
    range: `'Data Monthly'!${c}1:${c}29`,
    values,
    colIndex: nextCol,
    totalViews,
    totalCoreSales,
    totalBumpSales,
    totalAllSales: totalCoreSales + totalBumpSales,
    totalNewLeads,
    unsubscribes
  } 
}];

const today = new Date();

// First day of previous month
const firstDay = new Date(today.getFullYear(), today.getMonth() - 1, 1);

// Last day of previous month
const lastDay = new Date(today.getFullYear(), today.getMonth(), 0);

// Format as "Feb 1, 2026" for SamCart
const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const startDate = `${months[firstDay.getMonth()]} ${firstDay.getDate()}, ${firstDay.getFullYear()}`;
const endDate = `${months[lastDay.getMonth()]} ${lastDay.getDate()}, ${lastDay.getFullYear()}`;

return [{
  json: {
    startDate,
    endDate,
    startISO: firstDay.toISOString().split('T')[0],
    endISO: lastDay.toISOString().split('T')[0],
  }
}];

