// Get row 1 data from direct input (GET request)
const row1 = $input.first().json.values?.[0] || [];
const nextCol = row1.length;

function colToLetter(col) {
  let letter = '';
  while (col >= 0) {
    letter = String.fromCharCode((col % 26) + 65) + letter;
    col = Math.floor(col / 26) - 1;
  }
  return letter;
}

const colLetter = colToLetter(nextCol);
const c = colLetter;

// Calculate next month from the last column header
const lastDateStr = row1[row1.length - 1];
const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const parts = lastDateStr.split(' ');
const monthIndex = monthNames.indexOf(parts[0]);
const year = parseInt(parts[1]);

const nextMonthDate = new Date(year, monthIndex + 1, 1);
const monthHeader = `${monthNames[nextMonthDate.getMonth()]} ${nextMonthDate.getFullYear()}`;

const values = [
  [monthHeader],                                                                          // Row 1: Month header
  [`='Data Monthly'!${c}5+'Data Monthly'!${c}8+'Data Monthly'!${c}21`],                   // Row 2: LPP (legacy sales + core sales + order bump)
  [`='Data Monthly'!${c}11+'Data Monthly'!${c}22`],                                       // Row 3: NLP (core sales + order bump)
  [`='Data Monthly'!${c}14+'Data Monthly'!${c}23`],                                       // Row 4: AA (core sales + order bump)
  [`='Data Monthly'!${c}17+'Data Monthly'!${c}24`],                                       // Row 5: LS (core sales + order bump)
  [`='Data Monthly'!${c}20+'Data Monthly'!${c}25`],                                       // Row 6: EE (core sales + order bump)
  [''],                                                                                    // Row 7: 5-Course Bundle & Upgrades (empty)
  [`=SUM(${c}2:${c}6)`],                                                                  // Row 8: Total
  [`=${c}8/31`],                                                                           // Row 9: Daily average sales
  [''],                                                                                    // Row 10: blank
  [`='Data Monthly'!${c}3+'Data Monthly'!${c}6+'Data Monthly'!${c}9+'Data Monthly'!${c}12+'Data Monthly'!${c}15+'Data Monthly'!${c}18`], // Row 11: Total sales page views
  [`=${c}8/${c}11`],                                                                       // Row 12: Conversion rate
];

return [{ 
  json: { 
    range: `'Sales & page views'!${c}1:${c}12`,
    values,
    colIndex: nextCol,
    colLetter: c
  } 
}];

