// n8n Code Node — Format as separate Slack messages per section
const items = $input.all();

const today = new Date().toLocaleDateString('en-GB', {
  weekday: 'long',
  day: 'numeric',
  month: 'long',
  year: 'numeric'
});

const allCitations = [];
const sectionLabels = [
  ':office:  *Major AI Company Updates*',
  ':fire:  *Viral & Trending in AI*',
  ':chart_with_upwards_trend:  *Funding, Policy & Research*'
];

const messages = [];
let storyNum = 0;

// Header message
messages.push({
  slack_text: `:newspaper:  *AI Briefing — ${today}*\n_Everything that matters in AI today_\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`,
  is_header: true
});

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;

  let content = '';
  if (data.choices?.[0]?.message?.content) {
    content = data.choices[0].message.content;
  }

  const citations = data.citations || [];
  allCitations.push(...citations);

  // Clean preamble and trailing text
content = content.replace(/^[\s\S]*?(?=## 1\.)/s, '').trim();


  const stories = content.split(/(?=## \d+\.)/).filter(s => s.trim());

  if (stories.length === 0) continue;

  let sectionText = `${sectionLabels[i] || ':bulb:  *Other Updates*'}\n`;

  for (const story of stories) {
    storyNum++;

    let formatted = story
      .replace(/## \d+\./, `## ${storyNum}.`)
      .replace(/\[(\d+)\]/g, '')
      .replace(/## (\d+)\.\s*(.+)/g, '\n*$1. $2*')
      .replace(/\*\*Source:\*\*\s*\[([^\]]+)\]\(([^)]+)\)/g, '_Source: <$2|$1>_')
      .replace(/\*\*Source:\*\*\s*(.+)/g, '_Source: $1_')
      .replace(/\*\*Summary:\*\*/g, '*Summary:*')
      .replace(/\*\*Why it matters:\*\*/g, '*Why it matters:*')
      .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>')
      .replace(/\*\*(.+?)\*\*/g, '*$1*')
      .replace(/\n{3,}/g, '\n\n')
      .trim();

    if (formatted.length > 10) {
      sectionText += `\n${formatted}\n`;
    }
  }

  messages.push({
    slack_text: sectionText.trim(),
    is_header: false
  });
}

// Footer message
const uniqueUrls = [...new Set(allCitations)].slice(0, 5);
if (uniqueUrls.length > 0) {
  messages.push({
    slack_text: uniqueUrls.join('\n'),
    is_header: false
  });
}

messages.push({
  slack_text: `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n:robot_face:  _Automated via Perplexity Sonar + n8n_`,
  is_header: false
});

return messages.map(m => ({ json: m }));

